import java.util.Scanner;

public class SecureBufferExample {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter your name: ");
        String name = scanner.nextLine();

        // Ensure buffer size does not exceed input length
        int bufferSize = Math.min(name.length(), 10);

        char[] buffer = new char[bufferSize];
        name.getChars(0, bufferSize, buffer, 0);

        System.out.println("Hello, " + new String(buffer));
    }
}

### Explanation:
취약유형: Buffer Overflow
